sys_script_include.script:
/**
 * @class Record
 * @description Base class for all record classes
 * @since 24/02/2026
 * @date  24/02/2026
 * @version 1.0.0
 * @author Thomas Grensemann E-Mail: <thomas.grensemann@t-systems.com>
 *
 */
class Record {

	/**
	 * constructor
	 */
	constructor() {
		this.LOG_HANDLER = new LoggingHandler();
	}

    /**
     * @description Writes a log message
     *
     * @param {String} result result of the operation 
	 * @param {String} source application
	 * @param {String} message log message
     * @param {String} reason reason of the operation
	 * @param {String} table The table to be used
     * @param {Object} properties property object
     *
     * @returns {String}  sys_id of the updated record. Returns null if the update fails.
     */
	// eslint-disable-next-line
    processResult(result, source, message, reason, table, properties) {

        if (result) {
            this.LOG_HANDLER.info(source, message + ' successful', reason, table, properties, {
                'targetRecord': result,
                'targetTable': table
            });
        } else {
            this.LOG_HANDLER.error(source, message + ' failed', reason, table, properties);
        }
    }

}
